plugins {
    kotlin("jvm") version "2.3.20"
    `maven-publish`
    signing
}

group = "io.github.sor2171"
version = "1.0.0"

publishing {
    publications {
        create<MavenPublication>("mavenJava") {
            from(components["java"])

            groupId = "io.github.sor2171"
            artifactId = "kaudioanalyser"
            version = version

            pom {
                name.set("KaudioAnalyser")
                description.set("A concise description of your library")
                url.set("https://github.com/sor2171/KaudioAnalyser")
                licenses {
                    license {
                        name.set("MIT License")
                        url.set("https://opensource.org/licenses/MIT")
                    }
                }
                developers {
                    developer {
                        id.set("sor2171")
                        name.set("SOR")
                        email.set("sor2171@foxmail.com")
                    }
                }
                scm {
                    connection.set("scm:git:github.com/sor2171/KaudioAnalyser.git")
                    developerConnection.set("scm:git:ssh://github.com/sor2171/KaudioAnalyser.git")
                    url.set("https://github.com/sor2171/KaudioAnalyser")
                }
            }
        }
    }
}

signing {
    val keyId = project.findProperty("signing.keyId") as String?
        ?: System.getenv("GPG_KEY_ID")
    val password = project.findProperty("signing.password") as String?
        ?: System.getenv("GPG_PASSWORD")

    val secretKeyFile = project.findProperty("signing.secretKeyRingFile") as String?
    val secretKey = System.getenv("GPG_SIGNING_KEY")

    println("DEBUG: KeyID is ${keyId != null}, Pass is ${password != null}, Key is ${secretKeyFile != null}")

    if (secretKeyFile != null) {
        println("DEBUG: secretKeyFile: ${File(secretKeyFile).readText()}")
        useInMemoryPgpKeys(
            keyId,
            File(secretKeyFile).readText(),
            password
        )
    } else {
        useInMemoryPgpKeys(
            keyId,
            secretKey,
            password
        )
    }

    sign(publishing.publications["mavenJava"])
}

repositories {
    mavenCentral()
}

dependencies {
    implementation("org.jetbrains.kotlinx:kotlinx-coroutines-core:1.8.0")
    testImplementation(kotlin("test"))
}

kotlin {
    jvmToolchain(17)
}

java {
    withSourcesJar()
    withJavadocJar()
}

tasks.test {
    useJUnitPlatform()
}

